// // This module decodes a 5-bit input into a 32-bit output where each bit corresponds to an input value. For example, if the input is 5'b00000, the output should be 32'b00000000000000000000000000000000.
module decoder_5to32 (  
    input [4:0] in,  
    output reg [31:0] out  
);  
    always @(*) begin  
        out = 32'b0; // Default to all outputs low  
        out[in] = 1'b1; // Set the appropriate output high  
    end  
endmodule
